.labels {
  margin-top: 10px;
  min-width: 0;
  max-height: none;
  overflow: visible;
  opacity: 1;
  row-gap: 6px;
  transform: none;
}

.labels span:not(.label-overflow) {
  max-width: min(100%, 168px);
}

.labels .label-overflow {
  flex: 0 0 auto;
  max-width: none;
  color: var(--relay-text-subtle);
}

.drag-handle {
  position: absolute;
  top: var(--relay-space-2);
  right: var(--relay-space-2);
  width: 28px;
  height: 28px;
  min-height: 28px;
  padding: 0;
  border-color: transparent;
  border-radius: var(--relay-radius-sm);
  background: transparent;
  color: var(--relay-text-subtle);
  box-shadow: none;
  opacity: 0.78;
