    color 160ms var(--relay-ease),
    background-color 160ms var(--relay-ease),
    box-shadow 160ms var(--relay-ease),
    opacity 160ms var(--relay-ease);
}

.ticket-card:hover .drag-handle,
.ticket-card:focus-within .drag-handle,
.ticket-card.keyboard-selected .drag-handle {
