.modal {
  width: min(920px, calc(100vw - 64px));
  max-height: calc(100dvh - 64px);
  overflow: auto;
  border: 0;
  border-radius: var(--relay-radius-lg);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 5%) 0%, transparent 34%),
    var(--relay-popover);
  color: var(--relay-text);
  padding: 20px;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 7%),
    var(--relay-shadow-modal);
  animation: surface-in 240ms var(--relay-spring) both;
}

.modal header,
.detail-header,
.agent-activity-panel header,
.agent-log-modal header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 14px;
}

.modal h2,
.modal p,
.detail-header h2,
.agent-activity-panel h3 {
  margin: 0;
}

.modal h2 {
  font-size: var(--relay-text-xl);
  font-weight: 580;
}

.modal p {
  margin-top: 4px;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-md);
}

.icon-button {
  width: 32px;
  min-height: 32px;
  padding: 0;
}

.modal-grid {
  display: grid;
  grid-template-columns: 1fr 184px;
  gap: var(--relay-space-3);
  margin-top: var(--relay-space-4);
  align-items: end;
}

.create-fields {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--relay-space-3);
  margin-top: var(--relay-space-4);
}

.create-type-fields {
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
}

.draft-actions {
  display: grid;
  gap: var(--relay-space-2);
}

.draft-message {
  margin-top: var(--relay-space-3);
  border: 0;
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 4%);
  color: var(--relay-text-muted);
  padding: 9px 11px;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  font-size: var(--relay-text-md);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.draft-message.error {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.ticket-suggestions-status {
  justify-content: flex-start;
}

.ticket-suggestions-status button {
  margin-left: auto;
}

.ticket-suggestions-empty {
  margin-top: var(--relay-space-4);
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 3%);
  padding: var(--relay-space-4);
  display: grid;
  gap: 6px;
  color: var(--relay-text-subtle);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.ticket-suggestions-empty strong {
  color: var(--relay-text);
  font-size: var(--relay-text-md);
}

.ticket-suggestions-list {
  display: grid;
  gap: var(--relay-space-3);
  margin-top: var(--relay-space-4);
}

.ticket-suggestion-row {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: start;
  gap: var(--relay-space-3);
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 3%);
  padding: var(--relay-space-3);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.ticket-suggestion-row.created {
  background: color-mix(in srgb, var(--relay-success-muted) 42%, transparent);
}

.ticket-suggestion-main {
  min-width: 0;
  display: grid;
  gap: var(--relay-space-2);
}

.ticket-suggestion-heading {
  min-width: 0;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.ticket-suggestion-heading h3 {
  margin: 0;
  min-width: 0;
  overflow-wrap: anywhere;
  color: var(--relay-text);
  font-size: var(--relay-text-base);
  font-weight: 590;
  line-height: 1.3;
}

.ticket-suggestion-labels {
  margin-top: 0;
}

.ticket-suggestion-row p {
  margin: 0;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-md);
  line-height: 1.45;
}

.ticket-suggestion-request {
  display: grid;
  gap: 4px;
  border-radius: var(--relay-radius-sm);
  background: rgb(0 0 0 / 14%);
  padding: 8px 10px;
}

.ticket-suggestion-request span {
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
  font-weight: 560;
}

.ticket-suggestion-request strong {
  overflow-wrap: anywhere;
  color: var(--relay-text);
  font-size: var(--relay-text-md);
  font-weight: 520;
  line-height: 1.45;
}

                      value={subticket.context}
                      onChange={(event) => updateSubticket(index, { context: event.target.value })}
                    />
                  </label>
                  {renderPlanListField("Codebase Findings", subticket.researchFindings, (value) => updateSubticket(index, { researchFindings: value }), "One finding per line")}
                  {renderPlanListField("Requirements", subticket.requirements, (value) => updateSubticket(index, { requirements: value }), "One requirement per line")}
                  {renderPlanListField(
                    "Implementation Plan",
                    subticket.implementationPlan,
                    (value) => updateSubticket(index, { implementationPlan: value }),
                    "One implementation step per line"
                  )}
                  {renderPlanListField("Test Plan", subticket.testPlan, (value) => updateSubticket(index, { testPlan: value }), "One test command or scenario per line")}
                  {renderPlanListField(
                    "Acceptance Criteria",
                    subticket.acceptanceCriteria,
                    (value) => updateSubticket(index, { acceptanceCriteria: value }),
                    "One acceptance criterion per line"
                  )}
                  {renderPlanListField("Assumptions", subticket.assumptions, (value) => updateSubticket(index, { assumptions: value }), "One assumption per line")}
                  {renderPlanListField(
                    "Open Questions",
                    subticket.clarificationQuestions,
                    (value) => updateSubticket(index, { clarificationQuestions: value }),
                    "One question per line"
                  )}
                  {renderPlanListField(
                    "Implementation Notes",
                    subticket.implementationNotes,
                    (value) => updateSubticket(index, { implementationNotes: value }),
                    "One note per line"
                  )}
                  <MarkdownBlock
                    className="ticket-markdown-preview compact"
                    source={markdownFromSubticketDraft(subticket, draft.title)}
                    title={`Subticket ${index + 1}`}
                    onCopied={(kind) => setToast(copyToast(kind))}
                    onCopyError={(error) =>
                      setToast({ kind: "error", message: error instanceof Error ? error.message : "Unable to copy." })
                    }
                  />
                </div>
              ))
            )}
          </div>
        )}
      </div>
    )}

    <div className="modal-footer" ref={modalFooterRef}>
      <button onClick={onClose}>Cancel</button>
      <button className="primary-button" onClick={save} disabled={saving || (!draft && manualTitle.trim().length === 0)}>
        {saving ? <Loader2 className="spin" size={16} /> : <Check size={16} />}
        {effectiveTicketType === "epic" ? "Create Epic" : "Create Ticket"}
      </button>
    </div>
  </section>
</div>

